{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラは2026-05-13付で正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10時から1時間で開催し、各部署から最低1名が参加する運用とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "第1フェーズのデータ移行はマスタ系のみとし、トランザクション系は移行せず旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証・マスタ配信の共通基盤はサクラ商事との共同利用案で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行テストと負荷テストはシステムテストと分けて別立てで実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "新システムのユーザー権限は既存のロール定義を流用し、ロール定義の再設計は今回の対象外とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "障害発生時の一次受け窓口は情報システム部ではなくQAチームとする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "移行方式は全拠点一括移行や並行稼働ではなく段階移行を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "本番リリース目標日は9月末案を撤回し、2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "切替作業は土曜深夜に実施する前提で進める。",
      "decided_by": "桐生 遥"
    }
  ],
  "action_items": [
